  deck      = excluded.deck,
  numero    = excluded.numero,
  tipo      = excluded.tipo,
  texto_pt  = excluded.texto_pt,
  texto_en  = excluded.texto_en,
  interrupt = excluded.interrupt,
  prompt_en = excluded.prompt_en;
