('C30','C',30,'Lugar','Ruínas','Ruin',true,'ancient ruins with broken bricks, dirt, burnt, destroyed, crumbling walls'),
('C31','C',31,'Personagem','Fada','Fairy',false,'a tiny fairy with iridescent wings hovering in a moonlit clearing, trailing silver stardust, cradling a glowing orb'),
